diff --git a/llvm/lib/Transforms/IPO/GlobalOpt.cpp b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
index d7edd1288309..f573da7a3662 100644
--- a/llvm/lib/Transforms/IPO/GlobalOpt.cpp
+++ b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
@@ -2551,7 +2551,9 @@ static bool OptimizeNonTrivialIFuncs(
         }))
       continue;

-    assert(!Callees.empty() && "Expecting successful collection of versions");
+      if (Callees.empty())
+        continue;
+      assert(!Callees.empty() && "Expecting successful collection of versions");

     LLVM_DEBUG(dbgs() << "Statically resolving calls to function "
                       << Resolver->getName() << "\n");

